import{_ as t,o,c as r,a3 as a}from"./chunks/framework.CjquFG0V.js";const h=JSON.parse('{"title":"42A. Employee Records","description":"","frontmatter":{"title":"42A. Employee Records","eba":"Doctors in Training 2022-2026","topics":["leave","wages","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/remuneration/42A-employee-records.md","filePath":"ebas/doctors-in-training/remuneration/42A-employee-records.md"}'),n={name:"ebas/doctors-in-training/remuneration/42A-employee-records.md"};function i(s,e,p,c,l,d){return o(),r("div",null,[...e[0]||(e[0]=[a('<h1 id="_42a-employee-records" tabindex="-1">42A. Employee Records <a class="header-anchor" href="#_42a-employee-records" aria-label="Permalink to &quot;42A. Employee Records&quot;">​</a></h1><p><strong>42A.1</strong> Employee Records</p><p><strong>(a)</strong> The Act and Regulations set out an Employer&#39;s obligations with respect to record keeping including but not limited to:</p><p><strong>(i)</strong> a requirement to keep a record that sets out any leave the employee takes and the balance (if any) of the employee&#39;s entitlement to that leave from time to time;</p><p><strong>(ii)</strong> the inspection and copying of an employee record by the employee or former employee to whom the record relates; and</p><p><strong>(iii)</strong> the requirement to keep accurate employee records.</p><p><strong>(b)</strong> Where an Employer records time and attendance on a Doctor’s electronic timecard in excess of the record keeping requirements of the Act and Regulations, a Doctor (or their representative) may request in writing that the Employer make copies of the electronic timecards available within 14 days.</p><p><strong>(c)</strong> An Employer is not in breach of this clause, the Act or the Regulations if records prescribed at (a) have not been retained and are unable to be produced.</p><p><strong>42A.2</strong> Payslips</p><p><strong>(a)</strong> The Act and Regulations set out an Employer&#39;s obligations with respect to pay slips, including but not limited to a requirement to specify:</p><p><strong>(i)</strong> the period to which the pay slip relates;</p><p><strong>(ii)</strong> the amount of wages to which the Employee is entitled;</p><p><strong>(iii)</strong> if an amount was deducted from the gross amount of the payment, the name or the name and number of the fund or account into which the deduction was paid; and</p><p><strong>(iv)</strong> the net amount for each payment.</p><p><strong>(b)</strong> To the extent reasonably practicable, payslips will record an Employee&#39;s accrued annual leave and personal leave.</p><p><strong>(c)</strong> Where an adjustment is made to the Doctor’s pay to reflect an error arising from another pay period (such as overpayment or an entitlement to an additional payment) the Doctor will be advised in writing.</p><p><strong>(d)</strong> Note: in the event of a proposed deduction for an overpayment, please see clause 46, Recovery of Overpayments.</p><p><strong>(e)</strong> Payslips are important to ensuring that Doctors can be satisfied they are being paid correctly. Where a Doctor has a query about the content of their payslip, the Doctor may:</p><p><strong>(i)</strong> raise that query with the Medical Workforce Unit or Payroll Department (where applicable); and</p><p><strong>(ii)</strong> request that the AMA, including the Ambassador, raise any query with the Medical Workforce Unit or Payroll Department (where applicable) on their behalf.</p><p>Plain language terms: personnel file, HR records.</p>',21)])])}const g=t(n,[["render",i]]);export{h as __pageData,g as default};
